<template>
  <div>
    <span>思极定位</span><br>

<table width="100%" border="0" cellpadding="0" cellspacing="0" bordercolor="#E8F6F7" bgcolor="#FFFFFF" class="BK">
  <tr>
    <td height="42" width="15%" align="center" bgcolor="#0A7E81" class="BK2">
    	<span class="STYLE2">经度：</span>
    </td>
    <td class="BK3" width="60%" id="EPlatitude"></td>
  </tr>
  <tr>
    <td height="42" width="15%" align="center" bgcolor="#0A7E81" class="BK4">
    	<span class="STYLE2">纬度：</span>
    </td>
    <td class="BK3" id="EPlongitude"></td>
  </tr>
</table>


<div class="space10"></div> 
<textarea class="textareaStyle1" id="EPtextarea"  readonly="readonly" @focus="handleFocus" @blur="handleBlur">位置信息</textarea>		
<div class="space10"></div>			



<table width="100%" border="0" cellspacing="0" cellpadding="0">
  <tr>
    <td width="25%">&nbsp;</td>
    <td width="45%">
    <table width="130" border="1" cellpadding="0" cellspacing="0" bordercolor="#FFFFFF" bgcolor="#0A7E81" @click="EPlocate()">
      <tr>
        <td height="50" align="center"><span class="STYLE4">获取当前位置</span></td>
      </tr>
    </table>
    </td>
    <td width="30%"><table width="80" border="1" cellpadding="0" cellspacing="0" bordercolor="#FFFFFF" bgcolor="#0A7E81"
    	@click="clearDataEP()">
      <tr>
        <td height="50" align="center"><span class="STYLE4">清除</span></td>
      </tr>
    </table></td>
  </tr>
</table>





<!--*******************************-->
<span>百度定位</span><br>
<span>坐标系：</span><br>
<span>IOS： bd0911</span><br>
<span>Android： bd0911</span><br>

<table width="100%" border="0" cellpadding="0" cellspacing="0" bordercolor="#E8F6F7" bgcolor="#FFFFFF" class="BK">
  <tr>
    <td height="42" width="15%" align="center" bgcolor="#0A7E81" class="BK2">
    	<span class="STYLE2">经度：</span>
    </td>
    <td class="BK3" width="60%" id="BDlatitude"></td>
  </tr>
  <tr>
    <td height="42" width="15%" align="center" bgcolor="#0A7E81" class="BK4">
    	<span class="STYLE2">纬度：</span>
    </td>
    <td class="BK3" id="BDlongitude"></td>
  </tr>
</table>


<div class="space10"></div> 
<textarea class="textareaStyle1" id="BDtextarea"  readonly="readonly" @focus="handleFocus" @blur="handleBlur">位置信息</textarea>		
<div class="space10"></div>			



<table width="100%" border="0" cellspacing="0" cellpadding="0">
  <tr>
    <td width="25%">&nbsp;</td>
    <td width="45%">
    <table width="130" border="1" cellpadding="0" cellspacing="0" bordercolor="#FFFFFF" bgcolor="#0A7E81" @click="BDlocate()">
      <tr>
        <td height="50" align="center"><span class="STYLE4">获取当前位置</span></td>
      </tr>
    </table>
    </td>
    <td width="30%"><table width="80" border="1" cellpadding="0" cellspacing="0" bordercolor="#FFFFFF" bgcolor="#0A7E81"
    	@click="clearDataBD()">
      <tr>
        <td height="50" align="center"><span class="STYLE4">清除</span></td>
      </tr>
    </table></td>
  </tr>
</table>
<br>





<!--*******************************-->







<span>Cordova 原生插件（不推荐）</span>
<br>
<span>android 使用Google坐标系</span>

<table width="100%" border="0" cellpadding="0" cellspacing="0" bordercolor="#E8F6F7" bgcolor="#FFFFFF" class="BK">
  <tr>
    <td height="42" width="15%" align="center" bgcolor="#0A7E81" class="BK2">
    	<span class="STYLE2">经度：</span>
    </td>
    <td class="BK3" width="60%" id="latitude"></td>
  </tr>
  <tr>
    <td height="42" width="15%" align="center" bgcolor="#0A7E81" class="BK4">
    	<span class="STYLE2">纬度：</span>
    </td>
    <td class="BK3" id="longitude"></td>
  </tr>
</table>


<div class="space10"></div> 
<textarea class="textareaStyle1" id="textarea"  readonly="readonly" @focus="handleFocus" @blur="handleBlur">位置信息</textarea>		
<div class="space10"></div>			



<table width="100%" border="0" cellspacing="0" cellpadding="0">
  <tr>
    <td width="25%">&nbsp;</td>
    <td width="45%">
    <table width="130" border="1" cellpadding="0" cellspacing="0" bordercolor="#FFFFFF" bgcolor="#0A7E81" @click="locate()">
      <tr>
        <td height="50" align="center"><span class="STYLE4">获取当前位置</span></td>
      </tr>
    </table>
    </td>
    <td width="30%"><table width="80" border="1" cellpadding="0" cellspacing="0" bordercolor="#FFFFFF" bgcolor="#0A7E81"
    	@click="clearData()">
      <tr>
        <td height="50" align="center"><span class="STYLE4">清除</span></td>
      </tr>
    </table></td>
  </tr>
</table>




<input type='button' @click="startLocation()" value='开始轨迹'></input>
<input type='button' @click="stopLocation()" value='停止轨迹'></input>
<input type='button' @click="getHistoryTrack()" value='获取轨迹'></input>

  </div>
</template>

<script>
export default {
  name: "location", // 这个名字推荐：大写字母开头驼峰法命名。
  props: {},
  components: {},
  directives: {},
  mixins: [],
  data() {
    return {
      ready: false,
    };
  },
  computed: {},
  created() {},
  mounted() {},
  activated() {},
  deactivated() {},
  watch: {},
  methods: {
    //标识cordova环境是否准备好,初始值为false

    onDeviceReady() {
      console.log("onDeviceReady()111--->start()");
      this.ready = true;
      this.getLocation(mam.navigator.geolocation);
      console.log("onDeviceReady()222--->end()");
    },
    /**
     * Get current location
     */
    getLocation(geo, opts) {
      console.log("getLocation()");

      // Success callback
      var success = function (p) {
        console.log("get location success" + JSON.stringify(p));

        lat = p.coords.latitude;
        lng = p.coords.longitude;
        var addr = p.address;
        $("#latitude").html(lng);
        $("#longitude").html(lat);
        document.getElementById("textarea").value = "位置信息：" + addr;
      };

      // Fail callback
      var fail = function (e) {
        console.log("getLocation fail callback with error code " + e.code);
      };

      // Get location
      geo.getCurrentPosition(
        success,
        fail,
        opts || { enableHighAccuracy: true }
      ); //, {timeout: 10000});
    },

    locate() {
      this.getLocation(mam.navigator.geolocation);
    },

    EPlocate() {
      mam.navigator.epgis.getLocation(
        this.EPsuccessCallback,
        this.EPerrorCallback
      );
    },
    EPsuccessCallback(v) {
      console.log("successCallback" + JSON.stringify(v));
      var lat1 = v.latitude;
      var lng1 = v.longitude;
      var addr1 = v.address;
      $("#EPlatitude").html(lng1);
      $("#EPlongitude").html(lat1);

      document.getElementById("EPtextarea").value = "位置信息：" + addr1;
    },

    EPerrorCallback(e) {
      console.log("GPS信息获取失败" + JSON.stringify(e));
    },

    /**
     *坐标系：
     *    IOS： bd0911
     *Android： bd0911
     **/
    BDlocate() {
      mam.navigator.gps.getLocation(
        this.successCallback,
        this.errorCallback,
        "bd09ll"
      );
    },
    successCallback(v) {
      console.log("successCallback" + JSON.stringify(v));
      var lat1 = v.latitude;
      var lng1 = v.longitude;
      var addr1 = v.address;
      $("#BDlatitude").html(lng1);
      $("#BDlongitude").html(lat1);

      document.getElementById("BDtextarea").value = "位置信息：" + addr1;
    },

    errorCallback(e) {
      console.log("GPS信息获取失败" + JSON.stringify(e));
    },

    clearDataEP() {
      document.getElementById("EPlatitude").innerHTML = "";
      document.getElementById("EPlongitude").innerHTML = "";
      document.getElementById("EPtextarea").value = "";
    },

    clearDataBD() {
      document.getElementById("BDlatitude").innerHTML = "";
      document.getElementById("BDlongitude").innerHTML = "";
      document.getElementById("BDtextarea").value = "";
    },

    clearData() {
      document.getElementById("latitude").innerHTML = "";
      document.getElementById("longitude").innerHTML = "";
      document.getElementById("textarea").value = "";
    },

    startLocation() {
      mam.navigator.track.startTrack(this.successCallback, this.errorCallback);
    },

    stopLocation() {
      mam.navigator.track.stopTrack(this.successCallback, this.errorCallback);
    },

    getHistoryTrack() {
      var json = {
        startTime: 0, //开始时间(毫秒)
        endTime: 0, //结束时间(毫秒)
        setProcessed: true, //设置需要纠偏
        setNeedDenoise: true, //设置需要去噪
        setNeedVacuate: true, //设置需要抽稀
        setNeedMapMatch: true, //设置需要绑定路线
        setTransportMode: 0, //设置交通方式为驾车(0:driving,1:riding,2:walking)
        setSupplementMode: 2, //设置里程填充方式为驾车(0:no_supplement,1:straight,2:driving,3:riding,4:walking)
      };
      mam.navigator.track.getHistoryTrack(
        json,
        this.successCallback,
        this.errorCallback
      );
    },
    handleBlur(e) {
      if(e.value == "") {
        e.value = "位置信息"
      }
    },
    handleFocus(e) {
      if(e.value == "位置信息") {
        e.value = ""
      }
    }
  },
};
</script>
